class SidebarContent extends HTMLElement{static get observedAttributes(){return["current-page"]}connectedCallback(){this.render()}attributeChangedCallback(){this.render()}render(){const e=this.getAttribute("current-page")||"",t=window.location.pathname.includes("/pages/")?"":"pages/",n=[{id:"postgresql",href:t+"postgresql.html",label:"PostgreSQL"},{id:"mysql",href:t+"mysql.html",label:"MySQL"},{id:"mongodb",href:t+"mongodb.html",label:"MongoDB"},{id:"redis",href:t+"redis.html",label:"Redis"},{id:"supabase",href:t+"supabase.html",label:"Supabase"},{id:"comparison",href:t+"comparison.html",label:"Сравнение"}].map((t=>{const n=t.id===e;return`<li><a href="${t.href}" class="${n?"active":""}">${t.label}</a></li>`})).join("");this.innerHTML=`\n      <div class="container sidebar-content">\n        <h2>Базы данных</h2>\n        <ul class="sidebar-nav">\n          ${n}\n        </ul>\n      </div>\n    `}}customElements.define("sidebar-content",SidebarContent);